6.表格\begin&#123;tabular&#125;&#123;cc&#125; \hline \makebox[0.4\textwidth][c]&#123;符号&#125;	&amp;  \makebox[0.5\textwidth][c]&#123;意义&#125; \\ \hline$C_&#123;O&#125;$	    &amp; 机会成本\\ \hline$R_&#123;t&#125;$    &amp; 载客时间（min) \\ \hline$W_&#123;t&#125;$    &amp; 等待时间（min)  \\ \hline$I_&#123;AVG&#125;$	    &amp; 全市平均收入  \\ \hline$I_&#123;R&#125; $  &amp; 相对收入  \\ \hline$I_&#123;AVGW&#125;$	    &amp; 机场载客平均收入 \\ \hline$M$	    &amp; 出租车司机所得的净收益 \\ \hline$W$	    &amp; 一位出租车司机一次工作向出租车公司缴纳的费用 \\ \hline$T_&#123;0&#125;$	    &amp; 一辆出租车进入蓄车池后需要等待的平均时间 \\ \hline$T_&#123;r&#125;$	    &amp; 出当地出租车平均的运营时间\\ \hline$n_&#123;i&#125;$	    &amp; 出租车司机所得的净收益 \\ \hline$v$	    &amp; 每个上车点的服务效率 \\ \hline$N$	    &amp; 停车道开设的上车点的个数 \\ \hline$\bar d$    &amp; 平均排队消耗时间 \\ \hline$\bar W$    &amp; 平均排队等待时间 \\ \hline$ n$    &amp; 蓄车池中出租车的数量 \\ \hline$t$    &amp; 一天中的时间（0&lt;t&lt;24） \\ \hline\end&#123;tabular&#125;
